const services = {"mendja":{"title":"Shërbesa 1 — Upgrade i Mendjes","password":"mendja","songs":["mendja-1","mendja-2","mendja-3","mendja-4","mendja-5"],"text":"Romakëve 12:2","intro":"Ndryshimi i vërtetë fillon nga mënyra si mendojmë.","icebreaker":{"title":"Filtri i mendjes","instructions":"Secili thotë një mendim negativ që njerëzit e përsërisin shpesh. Grupi e riformulon atë mendim sipas së vërtetës së Fjalës.","time":"8–10 minuta"},"points":[{"title":"Çdo ndryshim fillon në mendje","verse":"Romakëve 12:2","body":"Transformimi i jashtëm nuk zgjat kur mendja vazhdon të funksionojë me modelet e vjetra. Perëndia nis ndryshimin duke ripërtërirë mënyrën si shohim veten, të tjerët dhe të ardhmen.","example":"Dikush mund të ndryshojë punë, qytet ose marrëdhënie, por nëse vazhdon të mendojë “unë nuk vlej”, do ta marrë të njëjtën frikë me vete kudo.","question":"Cili mendim i përsëritur po ndikon më shumë në vendimet e tua sot?"},{"title":"Një jetë e re kërkon mendësi të re","verse":"Efesianëve 4:22–23","body":"Jeta e re në Krishtin kërkon që të heqim mënyrën e vjetër të arsyetimit dhe të lejojmë Frymën të formojë reagime të reja.","example":"Kur kritikohesh, versioni i vjetër sulmon ose mbyllet. Versioni i ri dëgjon, dallon të vërtetën dhe përgjigjet me hir.","question":"Në cilën situatë reagon ende sipas versionit të vjetër?"},{"title":"Mendo ndryshe nga bota","verse":"Filipianëve 4:8","body":"Bota ushqen krahasimin, frikën dhe vetëqendrimin. Besimtari zgjedh të mbushë mendjen me atë që është e vërtetë, e ndershme, e drejtë dhe e pastër.","example":"Në rrjetet sociale mund të ndihesh pas të tjerëve. Fjala të kujton se identiteti yt nuk matet me suksesin e dikujt tjetër.","question":"Cilin burim duhet ta kufizosh që mendja jote të ushqehet më shëndetshëm?"},{"title":"Çinstalo gënjeshtrat","verse":"2 Korintasve 10:5","body":"Jo çdo mendim që na vjen është i vërtetë. Ne e shqyrtojmë, e krahasojmë me Fjalën dhe e bëjmë rob ndaj Krishtit.","example":"Mendimi “nuk do të ndryshoj kurrë” zëvendësohet me të vërtetën se Perëndia vazhdon veprën e Tij në ne.","question":"Cilën gënjeshtër duhet ta emërtosh dhe ta refuzosh sot?"},{"title":"Instalo të vërtetën e Fjalës","verse":"Psalmi 119:11","body":"Mendja ripërtërihet vazhdimisht kur Fjala lexohet, meditohet dhe zbatohet. Upgrade-i nuk është një emocion i vetëm, por një ritëm i përditshëm.","example":"Një varg i shkruar në telefon dhe i përsëritur gjatë javës mund të ndryshojë mënyrën si përballon ankthin.","question":"Cilin varg do ta marrësh si të vërtetën tënde për këtë javë?"}],"discussion":["Si e dallojmë një mendim nga Perëndia nga një mendim i ushqyer nga frika?","Çfarë zakoni praktik mund të na ndihmojë të ripërtërijmë mendjen çdo ditë?","Cilat mendësi të kulturës sonë bien ndesh me Fjalën?","Si mund ta ndihmojmë njëri-tjetrin pa gjykuar në betejat mendore?"],"challenge":"Për 7 ditë, shkruaj çdo mëngjes një mendim të vjetër dhe një të vërtetë biblike që e zëvendëson."},"falja":{"title":"Shërbesa 2 — Upgrade në Falje","password":"falja","songs":["falja-1","falja-2","falja-3","falja-4","falja-5"],"text":"Efesianëve 4:31–32","intro":"Falja nuk është emocion; është një vendim që hap rrugën e lirisë.","icebreaker":{"title":"Çanta e rëndë","instructions":"Një person mban një çantë me disa sende të rënda. Për çdo “barrë” të përmendur, hiqet një send. Diskutoni si mosfalja na lodh.","time":"8 minuta"},"points":[{"title":"Falja nuk e justifikon gabimin","verse":"Efesianëve 4:31–32","body":"Të falësh nuk do të thotë të thuash se e keqja ishte e drejtë. Do të thotë t’ia dorëzosh Perëndisë të drejtën për gjykim dhe të mos ushqesh hakmarrjen.","example":"Mund të vendosësh kufij të shëndetshëm me dikë dhe njëkohësisht të mos jetosh duke kërkuar t’i kthesh të njëjtën dhimbje.","question":"Çfarë ke ngatërruar deri tani me faljen: pajtimin, harresën apo mungesën e kufijve?"},{"title":"Falja të çliron ty","verse":"Kolosianëve 3:13","body":"Mosfalja e lidh zemrën me ngjarjen dhe personin që na lëndoi. Falja nuk ndryshon të shkuarën, por ndryshon pushtetin që ajo ka mbi të tashmen.","example":"Sa herë përmendet emri i dikujt, trupi yt tensionohet. Falja nis procesin që ai emër të mos kontrollojë më paqen tënde.","question":"Çfarë po të kushton emocionalisht mbajtja e mosfaljes?"},{"title":"Zemra që nuk fal ngec","verse":"Mateu 18:21–35","body":"Jezusi lidh faljen që japim me vetëdijen për mëshirën që kemi marrë. Kur harrojmë hirin, bëhemi të ashpër ndaj të tjerëve.","example":"Një gabim i vogël i dikujt na duket i pafalshëm, ndërsa gabimet tona i shpjegojmë me rrethanat.","question":"Ku po kërkon standard më të lartë nga të tjerët sesa nga vetja?"},{"title":"Jezusi është modeli ynë","verse":"Luka 23:34","body":"Jezusi fali në kulmin e padrejtësisë. Falja e krishterë nuk buron nga forca jonë, por nga Krishti që jeton në ne.","example":"Ndonjëherë hapi i parë nuk është të ndjesh falje, por të lutesh: “Zot, më jep gatishmëri të dua të fal.”","question":"Cili është hapi i parë i bindjes që mund të bësh sot drejt faljes?"}],"discussion":["A mund të falim pa u pajtuar menjëherë? Pse?","Kur duhen vendosur kufij pas faljes?","Si dallojmë procesin e faljes nga mohimi i dhimbjes?","Si mund ta mbështesë grupi dikë që po përballet me një plagë të thellë?"],"challenge":"Shkruaj emrin e një personi që duhet t’ia dorëzosh Perëndisë dhe lutu për të për 5 ditë pa kërkuar asgjë kundër tij."},"dashuria":{"title":"Shërbesa 3 — Upgrade në Dashuri","password":"dashuria","songs":["dashuria-1","dashuria-2","dashuria-3","dashuria-4","dashuria-5"],"text":"1 Korintasve 13","intro":"Dashuria e Krishtit nuk është vetëm ndjenjë; ajo shihet në mënyrën si sillemi.","icebreaker":{"title":"Gjuha e vlerësimit","instructions":"Secili zgjedh një person në grup dhe i thotë një cilësi konkrete që ka parë tek ai, pa përdorur komplimente të përgjithshme.","time":"10 minuta"},"points":[{"title":"Dashuria duron","verse":"1 Korintasve 13:4","body":"Durimi është dashuri që i jep tjetrit kohë të rritet. Nuk e ul standardin, por refuzon ta trajtojë tjetrin si projekt urgjent.","example":"Një shok përsërit të njëjtin gabim. Dashuria nuk e poshtëron para të tjerëve, por flet sinqerisht dhe qëndron pranë tij.","question":"Me kë e humbet durimin më shpejt dhe çfarë zbulon kjo për pritshmëritë e tua?"},{"title":"Dashuria fal dhe nuk mban llogari","verse":"1 Korintasve 13:5","body":"Dashuria nuk mban një regjistër të gabimeve për t’i përdorur në konfliktin e ardhshëm. Ajo trajton çështjen, kërkon të vërtetën dhe refuzon manipulimin.","example":"Në një debat, tundohesh të sjellësh pesë gabime të vjetra që nuk lidhen me situatën. Dashuria qëndron te çështja e sotme.","question":"Cilin “regjistër të vjetër” vazhdon ta hapësh në marrëdhëniet e tua?"},{"title":"Dashuria sakrifikon","verse":"1 Gjonit 3:16–18","body":"Dashuria biblike kushton kohë, rehati dhe vëmendje. Nuk kufizohet te fjalët, por bëhet vepër konkrete.","example":"Një mik ka nevojë të dëgjohet kur ti ke planifikuar të pushosh. Sakrifica mund të jetë t’i japësh praninë tënde pa telefon në dorë.","question":"Ku mund ta kthesh dashurinë nga qëllim i mirë në veprim konkret?"},{"title":"Dashuria nuk kërkon interesin e vet","verse":"Filipianëve 2:3–4","body":"Dashuria pyet jo vetëm “çfarë dua unë?”, por edhe “çfarë i shërben tjetrit?”. Kjo nuk do të thotë të humbasësh identitetin, por të heqësh egoizmin nga qendra.","example":"Në organizimin e një aktiviteti, zgjedhja jote nuk pranohet. Dashuria të lejon të mbështesësh grupin pa u tërhequr me inat.","question":"Në cilën marrëdhënie kërkon më shumë të marrësh sesa të japësh?"}],"discussion":["Si ndryshon dashuria biblike nga tolerimi i çdo sjelljeje?","Cili është armiku më i madh i dashurisë në marrëdhëniet tona?","Si mund të duam dikë me të cilin nuk kemi afërsi natyrore?","Çfarë do të thotë që bota na njeh si dishepuj nga dashuria?"],"challenge":"Bëj një akt dashurie të fshehtë për dikë, pa kërkuar falënderim ose njohje."},"fjalet":{"title":"Shërbesa 4 — Upgrade në Fjalët e tua","password":"fjalet","songs":["fjalet-1","fjalet-2","fjalet-3","fjalet-4","fjalet-5"],"text":"Jakobi 3","intro":"Fjalët tona zbulojnë zemrën dhe krijojnë atmosferë rreth nesh.","icebreaker":{"title":"Ndërtoje historinë","instructions":"Njëri nis një histori me një fjali pozitive. Secili shton nga një fjali. Në raundin e dytë, një fjali negative e ndryshon krejt drejtimin. Diskutoni fuqinë e fjalëve.","time":"8–10 minuta"},"points":[{"title":"Gjuha ndërton ose shkatërron","verse":"Fjalët e Urta 18:21","body":"Fjalët mund t’i japin kurajë një njeriu ose ta mbyllin atë. Ato mund të krijojnë besim, por edhe plagë që mbahen mend gjatë.","example":"Një drejtues thotë “ti nuk je për këtë punë” dhe personi heq dorë. Një fjali tjetër—“ke nevojë të rritesh, por unë besoj tek ti”—hap rrugë.","question":"Cila fjalë e dikujt ka ndikuar fort tek ti, për mirë ose për keq?"},{"title":"Fjalët zbulojnë zemrën","verse":"Mateu 12:34","body":"Kur presioni rritet, goja nxjerr atë që zemra ka grumbulluar. Prandaj ndryshimi i gjuhës kërkon edhe shërimin e burimit të brendshëm.","example":"Në trafik ose lodhje, del një ashpërsi që zakonisht e fshehim. Problemi nuk është vetëm situata, por çfarë po mbartim brenda.","question":"Në cilat rrethana fjalët e tua bëhen më të ashpra?"},{"title":"Bekimi dhe mallkimi nuk shkojnë bashkë","verse":"Jakobi 3:9–10","body":"Nuk mund ta adhurojmë Perëndinë dhe pastaj të poshtërojmë njerëzit e krijuar sipas shëmbëlltyrës së Tij. Integriteti përfshin edhe bisedat private.","example":"Pas shërbesës këndojmë, por në makinë përqeshim dikë. Upgrade-i kërkon të njëjtën gojë edhe në skenë, edhe jashtë saj.","question":"Cili lloj bisede private nuk përputhet me adhurimin tënd publik?"},{"title":"Fol jetë","verse":"Efesianëve 4:29","body":"Të flasësh jetë nuk do të thotë të shmangësh të vërtetën. Do të thotë ta thuash të vërtetën në mënyrë që ndërton dhe i jep hir dëgjuesit.","example":"Në vend të “ti gjithmonë dështon”, thuaj: “Ky vendim na lëndoi; le të gjejmë një mënyrë më të mirë.”","question":"Cilën bisedë duhet ta bësh ndryshe këtë javë?"}],"discussion":["Kur heshtja është më e mençur se të folurit?","Si mund të korrigjojmë dikë pa e turpëruar?","Çfarë roli ka humori në plagosjen ose ndërtimin e njerëzve?","Si mund ta ndryshojmë kulturën e thashethemeve në një grup?"],"challenge":"Për një ditë të plotë, mos thuaj asnjë fjalë për dikë që nuk do ta thoshe edhe në praninë e tij."},"besimi":{"title":"Shërbesa 5 — Upgrade në Besim","password":"besimi","songs":["besimi-1","besimi-2","besimi-3","besimi-4","besimi-5"],"text":"Hebrenjve 11","intro":"Besimi nuk mohon realitetin; ai i beson Perëndisë përtej asaj që sheh.","icebreaker":{"title":"Udhëzimi me sy mbyllur","instructions":"Në çifte, një person mbyll sytë dhe tjetri e udhëzon në një rrugë të shkurtër vetëm me zë. Më pas ndërroni rolet dhe diskutoni besimin.","time":"10 minuta"},"points":[{"title":"Mos jeto vetëm nga logjika","verse":"2 Korintasve 5:7","body":"Logjika është dhuratë, por nuk është zot. Ka momente kur bindja ndaj Perëndisë na çon përtej asaj që mund të kontrollojmë ose parashikojmë.","example":"Ndien thirrje të shërbesh, por pret të ndihesh 100% gati. Besimi fillon me hapin e parë, jo me sigurinë e plotë.","question":"Ku po kërkon garanci totale para se t’i bindesh Perëndisë?"},{"title":"Perëndia kërkon hapa besimi","verse":"Hebrenjve 11:8","body":"Abrahami u nis pa e ditur të gjithë hartën. Shpesh Perëndia jep dritë për hapin e ardhshëm, jo për gjithë udhëtimin.","example":"Të kërkosh falje, të aplikosh për një mundësi ose të nisësh një shërbesë mund të jetë hapi i vogël që hap rrugën.","question":"Cili është hapi i qartë që e di se duhet të bësh?"},{"title":"Frika mban versionin e vjetër","verse":"Mateu 14:29–31","body":"Pjetri eci mbi ujë kur sytë ishin te Jezusi dhe u fundos kur u përqendrua te era. Frika e zmadhon pengesën dhe e zvogëlon praninë e Perëndisë.","example":"Një mundësi e re shfaqet, por mendja prodhon vetëm skenarë dështimi. Besimi nuk i mohon rreziqet, por nuk u jep atyre fjalën e fundit.","question":"Cila frikë po të mban në vend?"},{"title":"Besimi sjell versionin e ri","verse":"Jakobi 2:17","body":"Besimi i gjallë bëhet veprim. Nuk mjafton të themi se besojmë; zgjedhjet tona duhet të tregojnë se Perëndia është i besueshëm.","example":"Beson se Perëndia siguron, por nuk menaxhon asgjë me besnikëri. Veprimi i besimit mund të jetë një buxhet i ndershëm dhe bujari e qëllimshme.","question":"Cili veprim do ta bëjë besimin tënd të dukshëm këtë javë?"}],"discussion":["Cili është dallimi mes besimit dhe pamaturisë?","Pse ndonjëherë Perëndia nuk na tregon gjithë planin?","Si e përballojmë zhgënjimin kur rezultati nuk është ai që prisnim?","Cili dëshmim personal na ka rritur besimin?"],"challenge":"Bëj brenda 48 orëve një hap konkret që e ke shtyrë nga frika, pasi ta kesh lutur dhe këshilluar me mençuri."},"disiplina":{"title":"Shërbesa 6 — Upgrade në Disiplinë","password":"disiplina","songs":["disiplina-1","disiplina-2","disiplina-3","disiplina-4","disiplina-5"],"text":"1 Timoteut 4:7–8","intro":"Versioni i ri kërkon zakone të reja dhe besnikëri në gjërat e vogla.","icebreaker":{"title":"Sfida 30-sekondëshe","instructions":"Secili zgjedh një veprim të thjeshtë dhe përpiqet ta përsërisë saktë për 30 sekonda. Diskutoni si ritmi dhe përsëritja ndërtojnë aftësi.","time":"7 minuta"},"points":[{"title":"Disiplina është frymore","verse":"1 Timoteut 4:7–8","body":"Disiplina nuk është armike e hirit. Ajo krijon hapësirë që dëshirat e mira të bëhen jetë e qëndrueshme.","example":"Të duash të lutesh nuk mjafton nëse nuk cakton kohë dhe vend. Një alarm i thjeshtë mund ta kthejë dëshirën në ritëm.","question":"Në cilën fushë mbështetesh vetëm te motivimi?"},{"title":"Menaxho kohën","verse":"Efesianëve 5:15–16","body":"Koha është një burim që tregon prioritetet reale. Disiplina thotë “jo” ndaj disa gjërave që të mund të thuash “po” ndaj asaj që ka vlerë.","example":"Thua se nuk ke kohë për Fjalën, por telefoni tregon dy orë në rrjete sociale. Problemi nuk është vetëm mungesa e kohës, por shpërndarja e saj.","question":"Cili zakon po ta konsumon kohën pa të dhënë jetë?"},{"title":"Menaxho trupin dhe financat","verse":"1 Korintasve 6:19–20","body":"Trupi dhe paratë janë pjesë e administrimit frymor. Kujdesi, kufijtë dhe planifikimi janë mënyra për ta nderuar Perëndinë.","example":"Blerjet impulsive sjellin ankth në fund të muajit. Një buxhet i thjeshtë krijon liri për të dhënë dhe për të planifikuar.","question":"Cila zgjedhje praktike do të sillte më shumë rregull në trup ose financa?"},{"title":"Mos u lodh duke bërë mirë","verse":"Galatasve 6:9","body":"Rezultatet e disiplinës shpesh vijnë ngadalë. Besnikëria vazhdon edhe kur nuk ka duartrokitje ose ndryshim të menjëhershëm.","example":"Lexon çdo ditë pak, por nuk ndien emocion të madh. Pas disa muajsh, Fjala fillon të formojë vendimet e tua.","question":"Ku ke nevojë të vazhdosh pa u dorëzuar?"},{"title":"Vrapo me qëllim","verse":"1 Korintasve 9:24–27","body":"Disiplina kërkon një qëllim të qartë. Nuk heqim dorë nga gjëra vetëm për të vuajtur, por për të fituar atë që ka vlerë të përjetshme.","example":"Një atlet zgjedh rutinën sepse e di garën. Edhe ne kemi nevojë të dimë për çfarë po stërvitemi frymërisht.","question":"Cili është qëllimi frymor që do të udhëheqë zakonet e tua këtë muaj?"}],"discussion":["Si dallon disiplina e shëndetshme nga legalizmi?","Cili zakon i vogël jep efektin më të madh?","Si mund të krijojmë përgjegjshmëri pa kontrolluar njëri-tjetrin?","Çfarë duhet të heqim nga rutina për të krijuar hapësirë për të rëndësishmen?"],"challenge":"Zgjidh një zakon 15-minutësh dhe praktikoje në të njëjtën orë për 14 ditë."},"misioni":{"title":"Shërbesa 7 — Upgrade në Mision","password":"misioni","songs":["misioni-1","misioni-2","misioni-3","misioni-4","misioni-5"],"text":"Mateu 28:18–20","intro":"Besimi nuk është vetëm për ne; jemi dërguar të bëjmë dishepuj.","icebreaker":{"title":"Harta e ndikimit","instructions":"Secili vizaton tre rrethe: familje, punë/shkollë dhe miq. Shkruan nga një emër në secilin rreth për të cilin dëshiron të jetë dëshmi.","time":"10 minuta"},"points":[{"title":"Besimi nuk është vetëm për veten","verse":"Mateu 28:19–20","body":"Jezusi nuk na thërret vetëm të marrim, por të shkojmë, të mësojmë dhe të ndihmojmë të tjerët të ndjekin Atë.","example":"Mund të konsumosh predikime çdo javë dhe prapë të mos investosh në asnjë person. Misioni e kthen dijen në ndikim.","question":"Kush po rritet në besim sepse ti je pranë tij?"},{"title":"Fuqia vjen nga Fryma","verse":"Veprat 1:8","body":"Misioni nuk mbështetet te personaliteti ynë. Fryma e Shenjtë na jep guxim, dashuri dhe fjalët e duhura për të dëshmuar.","example":"Nuk je tip shumë komunikues, por mund të ndash thjesht historinë tënde me sinqeritet me një koleg.","question":"Në cilën situatë ke nevojë të kërkosh fuqinë e Frymës dhe jo vetëbesimin?"},{"title":"Thuaj “Ja ku jam”","verse":"Isaia 6:8","body":"Perëndia kërkon gatishmëri para përsosmërisë. Njerëzit e disponueshëm bëhen instrumente në vende të zakonshme.","example":"Një nevojë shfaqet në kishë dhe të gjithë presin dikë tjetër. Misioni nis kur thua: “Mund të ndihmoj unë.”","question":"Ku po pret që dikush tjetër të bëjë atë që mund të nisësh ti?"},{"title":"Fol për Krishtin","verse":"Romakëve 10:14","body":"Veprat e mira janë të rëndësishme, por njerëzit kanë nevojë edhe të dëgjojnë lajmin e mirë. Dëshmia jonë duhet të jetë e dashur dhe e qartë.","example":"Një mik të pyet pse ke shpresë në një periudhë të vështirë. Ky është moment për të treguar se shpresa jote ka një emër: Jezus.","question":"Kujt mund t’ia tregosh historinë tënde me Krishtin në mënyrë të natyrshme?"},{"title":"Nga konsumator në ndërtues","verse":"Efesianëve 4:11–12","body":"Kisha nuk është një shërbim që konsumojmë, por një trup ku çdo pjesë kontribuon. Pjekuria pyet: “Çfarë mund të ndërtoj?”","example":"Në vend që vetëm të kritikosh një aktivitet, ofron një ide, kohë dhe përgjegjësi për ta përmirësuar.","question":"Cilin rol ndërtues mund të marrësh në komunitetin tënd?"}],"discussion":["Pse ndonjëherë kemi frikë të flasim për Krishtin?","Si mund të dëshmojmë pa qenë imponues?","Cili është ndryshimi mes një vendimi dhe bërjes së dishepujve?","Çfarë nevoje konkrete shohim rreth nesh si grup?"],"challenge":"Zgjidh një person, lutu për të çdo ditë dhe krijo një mundësi të sinqertë bisede brenda javës."},"dorezimi":{"title":"Shërbesa 8 — Upgrade në Dorëzim të Plotë","password":"dorezimi","songs":["dorezimi-1","dorezimi-2","dorezimi-3","dorezimi-4","dorezimi-5"],"text":"Romakëve 12:1","intro":"Kulmi i kampit nuk është më shumë informacion, por një jetë e vendosur në altarin e Perëndisë.","icebreaker":{"title":"Çfarë po mbaj fort?","instructions":"Secili mban një objekt në grusht për një minutë. Pastaj e lëshon dhe përshkruan ndryshimin. Lidheni me kontrollin dhe dorëzimin.","time":"7–8 minuta"},"points":[{"title":"Dorëzimi është adhurim","verse":"Romakëve 12:1","body":"Adhurimi nuk kufizohet te këngët. Trupi, koha, planet dhe zgjedhjet tona bëhen një ofertë e gjallë për Perëndinë.","example":"Këndon “të jap gjithçka”, por nuk e pyet Perëndinë për karrierën ose marrëdhëniet. Dorëzimi i bën edhe ato pjesë të adhurimit.","question":"Cilën fushë e ke mbajtur jashtë autoritetit të Perëndisë?"},{"title":"Lëre versionin e vjetër","verse":"Luka 9:23","body":"Të ndjekësh Jezusin përfshin mohimin e vetes—jo urrejtjen e vetes, por heqjen e egos nga froni.","example":"Versioni i vjetër kërkon gjithmonë të ketë të drejtë. Dorëzimi zgjedh të kërkojë falje edhe kur krenaria reziston.","question":"Cila sjellje e versionit të vjetër duhet të marrë fund?"},{"title":"Merr identitetin e ri","verse":"Galatasve 2:20","body":"Jeta e krishterë nuk është vetëm përmirësim personal; është Krishti që jeton në ne. Identiteti ynë nuk varet më nga performanca ose aprovimi.","example":"Kur dështon, nuk thua “jam dështim”, por “kam dështuar dhe po ngrihem si fëmijë i dashur i Perëndisë.”","question":"Cila etiketë e vjetër duhet të zëvendësohet me identitetin në Krishtin?"},{"title":"Lëri gjërat pas","verse":"Filipianëve 3:13–14","body":"Dorëzimi kërkon të mos jetojmë të lidhur pas lavdisë ose plagëve të së shkuarës. Ne shtrihemi drejt asaj që Perëndia ka përpara.","example":"Një sukses i vjetër mund të bëhet po aq pengesë sa një dështim, nëse refuzon të hysh në sezonin e ri.","question":"Çfarë nga e shkuara po të pengon të ecësh përpara?"},{"title":"Jeto për Krishtin","verse":"2 Korintasve 5:15","body":"Upgrade-i i vërtetë vazhdon pas kampit. Dorëzimi bëhet vendim i përditshëm për të jetuar jo për veten, por për Atë që vdiq dhe u ringjall.","example":"Të hënën, kthimi te puna, familja dhe përgjegjësitë bëhet vendi ku provohet vendimi i së dielës.","question":"Cili vendim konkret do të tregojë se kampi nuk ishte vetëm emocion?"}],"discussion":["Çfarë do të thotë praktikisht “sakrificë e gjallë”?","Pse kontrolli na duket më i sigurt se dorëzimi?","Si ruhet një vendim frymor pasi emocionet zbehen?","Çfarë zotimi mund të marrim si grup për 30 ditët e ardhshme?"],"challenge":"Shkruaj një deklaratë personale dorëzimi dhe ndaj një hap konkret me një person që do të të mbajë përgjegjës."}};

const dayOrder=['merkure','enjte','premte','shtune','diele'];
const dayLabels={merkure:'E Mërkurë',enjte:'E Enjte',premte:'E Premte',shtune:'E Shtunë',diele:'E Diel'};
let currentDay='merkure', pendingService=null;
const unlocked=new Set(JSON.parse(localStorage.getItem('upgradeUnlocked')||'[]'));

function renderNav(){const nav=document.getElementById('mainNav');nav.innerHTML=`<button class="nav-button active" data-view="details"><span class="nav-icon">⌂</span><span><strong>Detajet</strong><small>Transporti dhe akomodimi</small></span><b>→</b></button>`+dayOrder.map((d,i)=>`<button class="nav-button" data-view="${d}"><span class="nav-date">${15+i}</span><span><strong>${dayLabels[d]}</strong><small>${days[d].title}</small></span><b>→</b></button>`).join('');nav.querySelectorAll('button').forEach(b=>b.onclick=()=>openView(b.dataset.view));}
function openView(view){document.querySelectorAll('.nav-button').forEach(b=>b.classList.toggle('active',b.dataset.view===view));document.getElementById('detailsView').classList.toggle('active',view==='details');document.getElementById('dayView').classList.toggle('active',view!=='details');document.getElementById('pageTitle').textContent=view==='details'?'Detajet e organizimit':dayLabels[view];if(view!=='details'){currentDay=view;renderDay();}closeSidebar();window.scrollTo({top:0,behavior:'smooth'});}
function renderCars(filter=''){const term=filter.toLowerCase();document.getElementById('carGrid').innerHTML=cars.filter(c=>(c.driver+c.type+c.people.join(' ')).toLowerCase().includes(term)).map(c=>`<article class="car-card"><div class="car-head"><span>🚙</span><div><h4>${c.driver}</h4><p>${c.type}</p></div><b>${c.people.length}/${c.seats}</b></div><ul>${c.people.map((p,i)=>`<li><span>${i===0?'🧑‍✈️':'👤'}</span>${p}</li>`).join('')}</ul></article>`).join('');}
function renderAccommodation(day='merkure',filter=''){document.querySelectorAll('.day-tab').forEach(b=>b.classList.toggle('active',b.dataset.day===day));const term=filter.toLowerCase();const data=accommodation[day]||{};document.getElementById('accommodationGrid').innerHTML=Object.entries(data).filter(([u,p])=>(u+p.join(' ')).toLowerCase().includes(term)).map(([u,p])=>`<article class="unit-card"><div><span>${u==='Shtëpiza'?'🏠':'⛺'}</span><h4>${u}</h4></div><ul>${p.map(x=>`<li>👤 ${x}</li>`).join('')}</ul></article>`).join('');}
function setupAccommodation(){const tabs=document.getElementById('accommodationTabs');tabs.innerHTML=['merkure','enjte','premte','shtune'].map(d=>`<button class="day-tab ${d==='merkure'?'active':''}" data-day="${d}">${dayLabels[d]}</button>`).join('');tabs.querySelectorAll('button').forEach(b=>b.onclick=()=>{tabs.dataset.active=b.dataset.day;renderAccommodation(b.dataset.day,document.getElementById('accommodationSearch').value);});tabs.dataset.active='merkure';}
function renderDay(){const d=days[currentDay];dayDate.textContent=d.date;dayTitle.textContent=d.title;dayTheme.textContent=d.theme;dayVerse.textContent=d.verse;dayKeyword.textContent=d.keyword;scheduleTitle.textContent=dayLabels[currentDay];scheduleList.innerHTML=d.schedule.map(([t,a,icon])=>`<div class="timeline-item"><div class="time">${t}</div><div class="dot"></div><div class="activity"><span>${icon}</span><p>${a}</p></div></div>`).join('');servicesList.innerHTML=d.services.map(id=>renderService(id)).join('');personalNotes.value=localStorage.getItem(`notes-${currentDay}`)||'';}
function escapeHtml(value){return String(value).replace(/[&<>\"']/g,char=>({'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;',"'":'&#039;'}[char]));}
function getActiveModule(id){return localStorage.getItem(`service-module-${id}`)||'icebreaker';}
function setActiveModule(id,module){localStorage.setItem(`service-module-${id}`,module);}
function renderSongs(songIds){return `<section class="module-panel worship-module"><div class="module-title"><span>🎵</span><div><small>MODULI I ADHURIMIT</small><h4>Këngët e shërbesës</h4></div></div><p class="module-lead">Prek një titull për të hapur tekstin e plotë.</p><div class="songs-list">${songIds.map((songId,index)=>{const song=songs[songId];return `<details class="song-item"><summary><span class="song-number">${index+1}</span><span>${escapeHtml(song.title)}</span><b>＋</b></summary><div class="song-lyrics"><pre>${escapeHtml(song.lyrics)}</pre></div></details>`;}).join('')}</div></section>`;}
function getStep(id){return Number(localStorage.getItem(`sermon-step-${id}`)||0);}
function setStep(id,step){localStorage.setItem(`sermon-step-${id}`,String(step));}
function renderSermon(id,s){const step=Math.min(getStep(id),s.points.length-1),p=s.points[step],answer=localStorage.getItem(`sermon-answer-${id}-${step}`)||'';return `<section class="module-panel sermon-module"><div class="module-title"><span>📖</span><div><small>MODULI I PREDIKIMIT</small><h4>${s.text}</h4></div><b>${step+1}/${s.points.length}</b></div><div class="step-progress">${s.points.map((_,i)=>`<span class="${i<step?'done':i===step?'active':''}"></span>`).join('')}</div><article class="sermon-step"><span class="step-label">PIKA ${step+1}</span><h3>${escapeHtml(p.title)}</h3><div class="verse-card"><strong>📜 ${escapeHtml(p.verse)}</strong><p>Hape referencën në Biblën “Kristoforidhi i Dytë”.</p><a href="https://bibla.online/bibla" target="_blank" rel="noopener noreferrer">Lexo vargun e plotë ↗</a></div><p>${escapeHtml(p.body)}</p><div class="life-example"><strong>💡 Shembull nga jeta</strong><p>${escapeHtml(p.example)}</p></div><label class="reflection-label">💬 ${escapeHtml(p.question)}</label><textarea id="answer-${id}" rows="4" placeholder="Shkruaj përgjigjen për të vazhduar…">${escapeHtml(answer)}</textarea><div class="step-actions">${step>0?`<button class="secondary-action" onclick="previousPoint('${id}')">← Pika e mëparshme</button>`:'<span></span>'}<button class="primary-action next-point" onclick="nextPoint('${id}')">${step===s.points.length-1?'Përfundo predikimin ✓':'Pika tjetër →'}</button></div><p class="step-error" id="step-error-${id}"></p></article></section>`;}
function renderIcebreaker(s){return `<section class="module-panel icebreaker-module"><div class="module-title"><span>🧊</span><div><small>PARA PREDIKIMIT</small><h4>${escapeHtml(s.icebreaker.title)}</h4></div><b>${escapeHtml(s.icebreaker.time)}</b></div><p>${escapeHtml(s.icebreaker.instructions)}</p></section>`;}
function renderDiscussion(s){return `<section class="module-panel discussion-module"><div class="module-title"><span>🗣️</span><div><small>MODULI I DISKUTIMIT</small><h4>Bisedë në grup</h4></div></div><p class="module-lead">Mos kërkoni përgjigjen “perfekte”. Jepini hapësirë secilit të ndajë sinqerisht.</p><ol class="discussion-list">${s.discussion.map(q=>`<li>${escapeHtml(q)}</li>`).join('')}</ol></section>`;}
function renderChallenge(s){return `<section class="module-panel challenge-module"><div class="module-title"><span>🔥</span><div><small>MODULI I SFIDËS</small><h4>Hapi praktik</h4></div></div><p class="challenge-text">${escapeHtml(s.challenge)}</p><button class="primary-action accept-challenge" onclick="acceptChallenge(this)">✓ E pranoj sfidën</button></section>`;}
function renderService(id){const s=services[id],isOpen=unlocked.has(id),active=getActiveModule(id);const modules=[['icebreaker','🧊','Icebreaker'],['worship','🎵','Adhurimi'],['sermon','📖','Predikimi'],['discussion','🗣️','Diskutimi'],['challenge','🔥','Sfida']];return `<article class="service-card ${isOpen?'unlocked':''}" data-service="${id}"><div class="service-header"><div><span class="section-kicker">${s.text}</span><h3>${s.title}</h3><p>${s.intro}</p></div>${isOpen?'<span class="status-open">Hapur ✓</span>':`<button class="unlock-button" onclick="askPassword('${id}')">🔐 Hape</button>`}</div>${isOpen?`<div class="service-content"><div class="module-launcher">${modules.map(([key,icon,label])=>`<button class="module-launch-button ${active===key?'active':''}" onclick="openModule('${id}','${key}',this)"><span>${icon}</span><strong>${label}</strong><small>${active===key?'I hapur':'Hape modulin'}</small></button>`).join('')}</div><div class="module-stage"><div class="module-view ${active==='icebreaker'?'active':''}" data-module="icebreaker">${renderIcebreaker(s)}</div><div class="module-view ${active==='worship'?'active':''}" data-module="worship">${renderSongs(s.songs)}</div><div class="module-view ${active==='sermon'?'active':''}" data-module="sermon">${renderSermon(id,s)}</div><div class="module-view ${active==='discussion'?'active':''}" data-module="discussion">${renderDiscussion(s)}</div><div class="module-view ${active==='challenge'?'active':''}" data-module="challenge">${renderChallenge(s)}</div></div></div>`:''}</article>`;}
window.openModule=(id,name,button)=>{setActiveModule(id,name);const card=button.closest('.service-card');card.querySelectorAll('.module-launch-button').forEach(btn=>{const active=btn===button;btn.classList.toggle('active',active);const small=btn.querySelector('small');if(small)small.textContent=active?'I hapur':'Hape modulin';});card.querySelectorAll('.module-view').forEach(view=>view.classList.toggle('active',view.dataset.module===name));const stage=card.querySelector('.module-stage');if(stage)stage.scrollIntoView({behavior:'smooth',block:'start'});};
window.acceptChallenge=button=>{button.textContent='✓ Sfida u pranua';button.disabled=true;showToast('Sfida u pranua. Zbatoje gjatë ditës!');};
window.nextPoint=id=>{const s=services[id],step=Math.min(getStep(id),s.points.length-1),field=document.getElementById(`answer-${id}`),value=field.value.trim(),error=document.getElementById(`step-error-${id}`);if(value.length<3){error.textContent='Shkruaj një përgjigje të shkurtër përpara se të vazhdosh.';field.focus();return;}localStorage.setItem(`sermon-answer-${id}-${step}`,value);setActiveModule(id,'sermon');if(step<s.points.length-1){setStep(id,step+1);renderDay();setTimeout(()=>document.querySelector(`[data-service="${id}"] .module-stage`).scrollIntoView({behavior:'smooth',block:'start'}),40);}else{setActiveModule(id,'discussion');renderDay();showToast('Predikimi u përfundua. Tani hapet moduli i diskutimit.');setTimeout(()=>document.querySelector(`[data-service="${id}"] .module-stage`).scrollIntoView({behavior:'smooth',block:'start'}),40);}};
window.previousPoint=id=>{const step=getStep(id);if(step>0){setStep(id,step-1);setActiveModule(id,'sermon');renderDay();setTimeout(()=>document.querySelector(`[data-service="${id}"] .module-stage`).scrollIntoView({behavior:'smooth',block:'start'}),40);}};
window.askPassword=id=>{pendingService=id;modalTitle.textContent=services[id].title;passwordInput.value='';passwordError.textContent='';passwordModal.hidden=false;setTimeout(()=>passwordInput.focus(),50);};
passwordForm.onsubmit=e=>{e.preventDefault();if(passwordInput.value.trim().toLowerCase()===services[pendingService].password){unlocked.add(pendingService);localStorage.setItem('upgradeUnlocked',JSON.stringify([...unlocked]));passwordModal.hidden=true;renderDay();showToast('Shërbesa u hap me sukses.');}else passwordError.textContent='Password i pasaktë.';};
function showToast(msg){toast.textContent=msg;toast.classList.add('show');setTimeout(()=>toast.classList.remove('show'),2200);}
function closeSidebar(){sidebar.classList.remove('open');sidebarBackdrop.classList.remove('show');}
menuButton.onclick=()=>{sidebar.classList.add('open');sidebarBackdrop.classList.add('show');};sidebarBackdrop.onclick=closeSidebar;closeModal.onclick=()=>passwordModal.hidden=true;passwordModal.onclick=e=>{if(e.target===passwordModal)passwordModal.hidden=true;};togglePassword.onclick=()=>passwordInput.type=passwordInput.type==='password'?'text':'password';
lockAll.onclick=()=>{unlocked.clear();localStorage.removeItem('upgradeUnlocked');if(document.getElementById('dayView').classList.contains('active'))renderDay();showToast('Të gjitha shërbesat u bllokuan.');};
personalNotes.oninput=()=>localStorage.setItem(`notes-${currentDay}`,personalNotes.value);
carSearch.oninput=e=>renderCars(e.target.value);accommodationSearch.oninput=e=>renderAccommodation(accommodationTabs.dataset.active||'merkure',e.target.value);
renderNav();renderCars();setupAccommodation();renderAccommodation();
